export const BNav = /*#__PURE__*/ extend({
  name: NAME_NAV,
  functional: true,
  props,
  render(h, { props, data, children }) {
    const { tabs, pills, vertical, align, cardHeader } = props

    return h(
      props.tag,
      mergeData(data, {
        staticClass: 'nav',
        class: {
          'nav-tabs': tabs,
          'nav-pills': pills && !tabs,
          'card-header-tabs': !vertical && cardHeader && tabs,
          'card-header-pills': !vertical && cardHeader && pills && !tabs,
          'flex-column': vertical,
          'nav-fill': !vertical && props.fill,
          'nav-justified': !vertical && props.justified,
          [computeJustifyContent(align)]: !vertical && align,
          small: props.small
        }
      }),
      children
    )
  }
})

export const BSkeletonTable = /*#__PURE__*/ extend({
  name: NAME_SKELETON_TABLE,
  functional: true,
  props,
  render(h, { data, props }) {
    const { animation, columns } = props

    const $th = h('th', [h(BSkeleton, { props: { animation } })])
    const $thTr = h('tr', createArray(columns, $th))

    const $td = h('td', [h(BSkeleton, { props: { width: '75%', animation } })])
    const $tdTr = h('tr', createArray(columns, $td))
    const $tbody = h('tbody', createArray(props.rows, $tdTr))

    const $thead = !props.hideHeader ? h('thead', [$thTr]) : h()
    const $tfoot = props.showFooter ? h('tfoot', [$thTr]) : h()

    return h(BTableSimple, mergeData(data, { props: { ...props.tableProps } }), [
      $thead,
      $tbody,
      $tfoot
    ])
  }
})

const sortAccordionItems = () => {
  accordionItems.value = [...accordionItems.value].sort((a, b) =>
    sortSlotElementsByPosition(unref(a.el), unref(b.el))
  )
  if (modelValue.value) {
    if (isReadOnlyArray(modelValue.value)) {
      const next = modelValue.value
        .map((id) => accordionItems.value.findIndex((item) => item.id === id))
        .filter((i) => i !== -1)

      if (next.length !== modelValue.value.length) {
        if (process.env.NODE_ENV === 'development') {
          console.warn('[BAccordion] Unknown item id in v-model:', modelValue.value)
        }
      }
      index.value = next
    } else {
      const idx = accordionItems.value.findIndex((item) => item.id === modelValue.value)
      if (idx !== -1) index.value = idx
    }
  } else if (index.value !== undefined) {
    modelValue.value = isReadOnlyArray(index.value)
      ? index.value.map((idx) => accordionItems.value[idx]?.id).filter((el) => el !== undefined)
      : accordionItems.value[index.value]?.id
  }
}

import type { Ref } from 'vue'
import type { NLocale } from '../locales/common/enUS'
import type { NDateLocale } from '../locales/date/enUS'
import { computed, inject } from 'vue'
import { configProviderInjectionKey } from '../config-provider/src/context'
import { dateEnUS, enUS } from '../locales'

export default function useLocale<T extends keyof NLocale>(
  ns: T
): {
  localeRef: Ref<NLocale[T]>
  dateLocaleRef: Ref<NDateLocale>
} {
  const { mergedLocaleRef, mergedDateLocaleRef }
    = inject(configProviderInjectionKey, null) || {}
  const localeRef = computed(() => {
    return mergedLocaleRef?.value?.[ns] ?? enUS[ns]
  })
  const dateLocaleRef = computed(() => {
    return mergedDateLocaleRef?.value ?? dateEnUS
  })
  return {
    dateLocaleRef,
    localeRef
  }
}

